7	type Step = { label: string; status: 'done' | 'active' };
8	type PageStatus = { pageNum: number; status: 'loading' | 'done'; reviewCount?: number };
9	type IngestResult = { sessionId: string; session: Session };
10	
11	function sourceBadgeClass(source: string): string {
12	  const map: Record<string, string> = {
13	    trustpilot: 'bg-emerald-100 text-emerald-700',
14	    capterra: 'bg-orange-100 text-orange-700',
15	    appstore: 'bg-slate-100 text-slate-700',
16	    googleplay: 'bg-green-100 text-green-700',
17	    upload: 'bg-violet-100 text-violet-700',
18	  };
19	  return map[source] ?? 'bg-violet-100 text-violet-700';
20	}
21	
22	function sourceLabel(source: string): string {
23	  const map: Record<string, string> = {
24	    trustpilot: 'Trustpilot', capterra: 'Capterra', appstore: 'App Store',
25	    googleplay: 'Google Play', upload: 'CSV / JSONL Upload',
26	  };
27	  return map[source] ?? source;
28	}
