36	export default function NewSessionForm() {
37	  const router = useRouter();
38	  const [url, setUrl] = useState('');
39	  const [cap, setCap] = useState(50);
40	  const [loading, setLoading] = useState(false);
41	  const [error, setError] = useState('');
42	  const [dragover, setDragover] = useState(false);
43	  const [steps, setSteps] = useState<Step[]>([]);
44	  const [pages, setPages] = useState<PageStatus[]>([]);
45	  const [ingestResult, setIngestResult] = useState<IngestResult | null>(null);
46	  const fileRef = useRef<HTMLInputElement>(null);
47	
48	  async function fetchAndShowSummary(sessionId: string) {
49	    try {
50	      const res = await fetch(`/api/sessions/${sessionId}?limit=0`);
51	      if (!res.ok) throw new Error('fetch failed');
52	      const data = await res.json() as { session: Session };
53	      setIngestResult({ sessionId, session: data.session });
54	    } catch {
55	      router.push(`/session/${sessionId}`);
56	    }
57	  }
58	
59	  function pushStep(label: string) {
60	    setSteps(prev => [
61	      ...prev.map(s => s.status === 'active' ? { ...s, status: 'done' as const } : s),
62	      { label, status: 'active' },
63	    ]);
64	  }
65	
66	  async function ingestUrl() {
67	    if (!url.trim()) { setError('Enter a URL.'); return; }
68	    setLoading(true); setError(''); setSteps([]); setPages([]);
69	
70	    const es = new EventSource(`/api/sessions/stream?url=${encodeURIComponent(url)}&cap=${cap}`);
71	
72	    es.addEventListener('navigating', (e) => {
73	      const { message } = JSON.parse(e.data) as { message: string };
74	      pushStep(message);
75	    });
76	
77	    es.addEventListener('page-start', (e) => {
78	      const { pageNum, totalPages } = JSON.parse(e.data) as { pageNum: number; totalPages: number };
79	      setPages(prev => {
80	        // Initialise all slots on first page-start if totalPages known
81	        if (prev.length === 0 && totalPages > 1) {
82	          const slots: PageStatus[] = Array.from({ length: totalPages }, (_, i) => ({
83	            pageNum: i + 1,
84	            status: 'loading',
85	          }));
86	          return slots;
87	        }
88	        // Mark this page as loading if not already present
89	        if (prev.find(p => p.pageNum === pageNum)) return prev;
90	        return [...prev, { pageNum, status: 'loading' }];
91	      });
92	    });
93	
94	    es.addEventListener('page-done', (e) => {
95	      const { pageNum, totalPages, reviewCount } = JSON.parse(e.data) as { pageNum: number; totalPages: number; reviewCount: number };
96	      setPages(prev => {
97	        const updated = prev.map(p =>
98	          p.pageNum === pageNum ? { ...p, status: 'done' as const, reviewCount } : p
99	        );
100	        // Ensure page exists (handles page 1 whose page-start had totalPages=1)
101	        if (!updated.find(p => p.pageNum === pageNum)) {
102	          return [...Array.from({ length: totalPages }, (_, i) => ({
103	            pageNum: i + 1,
104	            status: (i + 1 === pageNum ? 'done' : 'loading') as 'done' | 'loading',
105	            reviewCount: i + 1 === pageNum ? reviewCount : undefined,
106	          }))];
107	        }
108	        return updated;
109	      });
110	    });
111	
112	    es.addEventListener('saving', (e) => {
113	      const { message } = JSON.parse(e.data) as { message: string };
114	      pushStep(message);
115	    });
116	
117	    es.addEventListener('done', (e) => {
118	      es.close();
119	      const { sessionId } = JSON.parse(e.data) as { sessionId: string };
120	      setSteps(prev => prev.map(s => ({ ...s, status: 'done' as const })));
121	      setLoading(false);
122	      void fetchAndShowSummary(sessionId);
123	    });
124	
125	    es.addEventListener('error', (e) => {
126	      es.close();
127	      setLoading(false);
128	      try {
129	        const { message } = JSON.parse((e as MessageEvent).data) as { message: string };
130	        setError(message);
131	      } catch {
132	        setError('Ingest failed. Check the URL and try again.');
133	      }
134	      setSteps([]);
135	      setPages([]);
136	    });
137	  }
138	
139	  async function ingestFile(file: File) {
140	    setLoading(true); setError('');
141	    const form = new FormData();
142	    form.append('file', file);
143	    try {
144	      const res = await fetch('/api/sessions', { method: 'POST', body: form });
145	      const data = await res.json() as { sessionId?: string; error?: string };
146	      if (!res.ok) { setError(data.error ?? 'Upload failed.'); return; }
147	      void fetchAndShowSummary(data.sessionId!);
148	    } catch {
149	      setError('Network error.');
150	    } finally {
151	      setLoading(false);
152	    }
153	  }
154	
155	  // ── Ingestion result summary screen ──────────────────────
156	  if (ingestResult) {
157	    const { sessionId, session } = ingestResult;
158	    const hasRating = session.ratingAvg != null;
159	    return (
160	      <div className="max-w-2xl mx-auto py-12 px-8">
161	        <div className="glass-card rounded-3xl p-8 shadow-xl shadow-violet-100">
162	          <div className="flex items-center gap-3 mb-6">
163	            <div className="w-10 h-10 rounded-full bg-emerald-100 flex items-center justify-center text-emerald-600 font-bold text-lg shrink-0">✓</div>
164	            <div>
165	              <p className="text-xs font-medium text-emerald-600 uppercase tracking-wider">Ingestion complete</p>
166	              <h2 className="text-2xl font-display font-bold leading-tight">{session.subjectName}</h2>
167	            </div>
168	            <span className={`ml-auto px-3 py-1 rounded-full text-xs font-medium ${sourceBadgeClass(session.source)}`}>
169	              {sourceLabel(session.source)}
170	            </span>
171	          </div>
172	
173	          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6 p-4 bg-slate-50 rounded-2xl">
174	            <div className="text-center">
175	              <p className="text-3xl font-bold text-violet-700">{session.reviewCount.toLocaleString()}</p>
176	              <p className="text-xs text-slate-500 mt-1">Reviews</p>
177	            </div>
178	            <div className="text-center">
179	              <p className="text-3xl font-bold text-violet-700">{session.verifiedCount.toLocaleString()}</p>
180	              <p className="text-xs text-slate-500 mt-1">Verified</p>
181	            </div>
182	            <div className="text-center">
183	              {hasRating ? (
184	                <>
185	                  <p className="text-3xl font-bold text-violet-700">{session.ratingAvg!.toFixed(1)}</p>
186	                  <p className="text-xs text-amber-500 mt-1">{renderStars(session.ratingAvg)}</p>
187	                </>
188	              ) : (
189	                <>
190	                  <p className="text-3xl font-bold text-slate-400">—</p>
191	                  <p className="text-xs text-slate-500 mt-1">Avg Rating</p>
192	                </>
